import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './Interview.css';

function Interview() {
  const navigate = useNavigate();
  const [step, setStep] = useState('upload'); // upload, interview, results
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [resumeData, setResumeData] = useState(null);
  const [sessionId, setSessionId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [currentAnswer, setCurrentAnswer] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile && selectedFile.type === 'application/pdf') {
      setFile(selectedFile);
    } else {
      alert('Please select a PDF file');
    }
  };

  const handleUpload = async () => {
    if (!file) return;

    setUploading(true);
    const formData = new FormData();
    formData.append('resume', file);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/resume/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });

      const data = await response.json();

      if (data.success) {
        setResumeData(data.extractedData);
        setStep('interview');
      } else {
        alert(data.message || 'Upload failed');
      }
    } catch (error) {
      alert('Network error. Please try again.');
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="interview-page">
      <div className="container-small">
        {step === 'upload' && (
          <div className="upload-section fade-in">
            <h1>Upload Your Resume</h1>
            <p className="subtitle">Upload your resume to get personalized interview questions</p>

            <div className="upload-card">
              <div className="upload-icon">📄</div>
              <h3>Drag and drop your resume here</h3>
              <p>or click to browse (PDF only, max 3 pages)</p>

              <input
                type="file"
                accept=".pdf"
                onChange={handleFileChange}
                className="file-input"
                id="resume-upload"
              />
              <label htmlFor="resume-upload" className="btn btn-secondary">
                Choose File
              </label>

              {file && (
                <div className="file-selected">
                  <p>✓ {file.name}</p>
                  <button 
                    onClick={handleUpload} 
                    className="btn btn-primary"
                    disabled={uploading}
                  >
                    {uploading ? 'Processing...' : 'Start Interview'}
                  </button>
                </div>
              )}
            </div>

            <div className="upload-info">
              <h4>Requirements:</h4>
              <ul>
                <li>PDF format only</li>
                <li>Maximum 3 pages</li>
                <li>Clear, readable text</li>
                <li>Valid resume content</li>
              </ul>
            </div>
          </div>
        )}

        {step === 'interview' && (
          <div className="interview-section fade-in">
            <h1>Interview in Progress</h1>
            <p className="subtitle">Answer the questions to the best of your ability</p>

            <div className="chat-container">
              <div className="message ai-message">
                <div className="message-avatar">🤖</div>
                <div className="message-content">
                  <p>Hello! I've reviewed your resume. Let's start with your experience. Can you tell me about your most recent project?</p>
                </div>
              </div>

              <div className="message-input-container">
                <textarea
                  className="message-input"
                  placeholder="Type your answer here..."
                  rows="4"
                ></textarea>
                <button className="btn btn-primary">Send Answer</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Interview;
